(2754, 1722, '_form', '<p><h3><b><font color=#0A65BA face=\"Comic Sans MS,arial,verdana\" >FORMULARIO DE CONTACTO</font></h3></b> </p>\n<br  />\n\n<p><font size=4 color=#2D98D5 face=\"Comic Sans MS,arial,verdana\">Nombre</font>\n    [text* your-name] </p>\n<br  />\n\n<p><font size=4 color=#2D98D5 face=\"Comic Sans MS,arial,verdana\">Celular\n</font>[tel* Celular] </p>\n<br  />\n\n<p><font size=4 color=#2D98D5 face=\"Comic Sans MS,arial,verdana\">Email</font>\n    [email* your-email] </p>\n<br  />\n\n<p><font size=4 color=#2D98D5 face=\"Comic Sans MS,arial,verdana\">Empresa</font>\n    [text* your-company] </p>\n<br  />\n\n<p><font size=4 color=#2D98D5 face=\"Comic Sans MS,arial,verdana\">RUC</font> \n[tel RUC]</p>\n<br  />\n\n[submit \"Enviar\"]'),
(2755, 1722, '_mail', 'a:9:{s:6:\"active\";b:1;s:7:\"subject\";s:28:\"Plata Perú \"[your-subject]\"\";s:6:\"sender\";s:38:\"Plata Perú <wordpress@miplata.com.pe>\";s:9:\"recipient\";s:22:\"alsanchez@tebca.com.pe\";s:4:\"body\";s:246:\"From: [your-name] <[your-email]>\n\nInformación: \n\nNombre: [your-name]\nEmpresa:[your-company]\nCorreo:  [your-email]\nCelular: [Celular]\nRUC: [RUC]\n\n\n-- \nThis e-mail was sent from a contact form on Plata Perú (https://stplatape.wpenginepowered.com)\";s:18:\"additional_headers\";s:22:\"Reply-To: [your-email]\";s:11:\"attachments\";s:0:\"\";s:8:\"use_html\";b:0;s:13:\"exclude_blank\";b:0;}'),
