(21, 3, '2016-04-05 20:57:29', '2016-04-05 20:57:29', '[vc_row css_animation=\"\" row_type=\"row\" type=\"full_width\" text_align=\"left\" padding_bottom=\"60px\" css=\".vc_custom_1460644053844{margin-top: 0px !important;border-top-width: 0px !important;border-bottom-width: 0px !important;}\"][vc_column css=\".vc_custom_1460644064988{border-top-width: 0px !important;padding-top: 0px !important;padding-bottom: 60px !important;}\"][rev_slider slidertitle=\"Homepage Slider Navidad\" alias=\"homepage-slider-1\"][/vc_column][/vc_row][vc_row css_animation=\"\" row_type=\"row\" type=\"full_width\" text_align=\"left\" background_color=\"#eff0f0\" css=\".vc_custom_1460529442547{margin-top: -60px !important;margin-right: -45% !important;margin-left: -45% !important;border-bottom-width: 80px !important;padding-top: 32px !important;padding-right: 90px !important;padding-bottom: 32px !important;padding-left: 90px !important;background-color: #eff0f0 !important;}\" el_class=\"full-width\"][vc_column width=\"1/4\" css=\".vc_custom_1629562939717{margin-right: 90px !important;margin-left: 90px !important;}\" offset=\"vc_hidden-sm vc_hidden-xs\"][/vc_column][vc_column width=\"1/4\" offset=\"vc_hidden-sm vc_hidden-xs\"][vc_column_text]\r\n<div class=\"left-icon\"><img class=\"alignnone size-full wp-image-705\" src=\"https://stplatape.wpenginepowered.com/wp-content/uploads/2016/04/Icono-Solucion-Eficaz.png\" alt=\"Icono Solucion Eficaz\" width=\"80\" height=\"80\" /></div>\r\n<div class=\"right-text\">\r\n<h2 class=\"twoitems\"><strong>Solución eficaz </strong></h2>\r\nOptimizamos su productividad y eficiencia con total confiabilidad y seguridad en las operaciones, disminuyendo así costos operativos\r\n\r\n</div>\r\n[/vc_column_text][/vc_column][vc_column width=\"1/4\" offset=\"vc_hidden-sm vc_hidden-xs\"][vc_column_text]\r\n<div class=\"left-icon\"><img class=\"alignnone size-full wp-image-706\" src=\"https://stplatape.wpenginepowered.com/wp-content/uploads/2016/04/Icono-Acceso-Global.png\" alt=\"Icono Acceso Global\" width=\"80\" height=\"80\" /></div>\r\n<div class=\"right-text\">\r\n<h2 class=\"twoitems\"><strong>Acceso global</strong></h2>\r\nCon nuestro sistema en línea, gestiona desde cualquier lugar solicitudes de tarjetas, recargas, consultas y emisión de reportes\r\n\r\n</div>\r\n[/vc_column_text][/vc_column][vc_column width=\"1/4\" css=\".vc_custom_1629562959305{margin-right: 90px !important;margin-left: 90px !important;}\" offset=\"vc_hidden-sm vc_hidden-xs\"][/vc_column][/vc_row][vc_row css_animation=\"\" row_type=\"row\" type=\"full_width\" text_align=\"left\" background_color=\"#eff0f0\" css=\".vc_custom_1629563002358{margin-top: -60px !important;margin-right: -45% !important;margin-left: -45% !important;border-bottom-width: 80px !important;padding-top: 32px !important;padding-right: 90px !important;padding-bottom: 32px !important;padding-left: 90px !important;background-color: #eff0f0 !important;}\" el_class=\"full-width\"][vc_column width=\"1/2\" offset=\"vc_hidden-lg vc_hidden-md\" css=\".vc_custom_1629563161271{padding-right: 60px !important;padding-left: 60px !important;}\"][vc_column_text]\r\n<div class=\"left-icon\"><img class=\"alignnone size-full wp-image-705\" src=\"https://stplatape.wpenginepowered.com/wp-content/uploads/2016/04/Icono-Solucion-Eficaz.png\" alt=\"Icono Solucion Eficaz\" width=\"80\" height=\"80\" /></div>\r\n<div class=\"right-text\">\r\n<h2 class=\"twoitems\"><strong>Solución eficaz </strong></h2>\r\nOptimizamos su productividad y eficiencia con total confiabilidad y seguridad en las operaciones, disminuyendo así costos operativos\r\n\r\n</div>\r\n[/vc_column_text][/vc_column][vc_column width=\"1/2\" offset=\"vc_hidden-lg vc_hidden-md\" css=\".vc_custom_1629563195490{padding-right: 60px !important;padding-left: 60px !important;}\"][vc_column_text]\r\n<div class=\"left-icon\"><img class=\"alignnone size-full wp-image-706\" src=\"https://stplatape.wpenginepowered.com/wp-content/uploads/2016/04/Icono-Acceso-Global.png\" alt=\"Icono Acceso Global\" width=\"80\" height=\"80\" /></div>\r\n<div class=\"right-text\">\r\n<h2 class=\"twoitems\"><strong>Acceso global</strong></h2>\r\nCon nuestro sistema en línea, gestiona desde cualquier lugar solicitudes de tarjetas, recargas, consultas y emisión de reportes\r\n\r\n</div>\r\n[/vc_column_text][/vc_column][/vc_row][vc_row css_animation=\"\" row_type=\"row\" type=\"grid\" text_align=\"left\" background_color=\"#ffffff\" css=\".vc_custom_1460507438630{margin-top: 40px !important;margin-bottom: -20px !important;}\"][vc_column width=\"1/3\"][vc_single_image image=\"1413\" img_size=\"266x181\" alignment=\"center\" onclick=\"custom_link\" qode_css_animation=\"\" link=\"/sobre-tebca/programas-plata/\"][vc_column_text el_class=\"blog-txt\"]\r\n<h4><a href=\"/sobre-tebca/programas-plata/\">Tarjeta Plata</a></h4>\r\n[/vc_column_text][vc_empty_space][/vc_column][vc_column width=\"1/3\"][vc_single_image image=\"1415\" img_size=\"266x181\" alignment=\"center\" onclick=\"custom_link\" qode_css_animation=\"\" link=\"/sobre-tebca/programas-plata-compras/\"][vc_column_text el_class=\"blog-txt\"]\r\n<h4><a href=\"/sobre-tebca/programas/#plata-compras\">Tarjeta Plata Compras</a></h4>\r\n[/vc_column_text][vc_empty_space][/vc_column][vc_column width=\"1/3\"][vc_single_image image=\"1416\" img_size=\"266x181\" alignment=\"center\" onclick=\"custom_link\" qode_css_animation=\"\" link=\"/sobre-tebca/programas-plata-gasolina/\"][vc_column_text el_class=\"blog-txt\"]\r\n<h4><a href=\"/sobre-tebca/programas/#plata-gasolina\">Tarjeta Plata Gasolina</a></h4>\r\n[/vc_column_text][vc_empty_space][/vc_column][/vc_row][vc_row css_animation=\"\" row_type=\"row\" type=\"full_width\" text_align=\"left\" background_color=\"#eff0f0\" css=\".vc_custom_1460757997444{margin-top: 60px !important;margin-right: -930% !important;margin-left: -930% !important;padding-top: 32px !important;padding-bottom: 32px !important;background-color: #eff0f0 !important;}\" el_class=\"f