(247, 3, '2016-04-12 07:51:10', '2016-04-12 07:51:10', '[vc_row css_animation=\"\" row_type=\"row\" type=\"grid\" text_align=\"left\" background_image=\"1475\" css=\".vc_custom_1482206305739{padding-top: 14px !important;padding-bottom: 73px !important;}\" el_class=\"full\"][vc_column el_class=\"black-btn\" css=\".vc_custom_1460386375532{margin-top: -50px !important;padding-top: 90px !important;padding-bottom: 100px !important;}\"][vc_column_text el_class=\"islider\" css=\".vc_custom_1480439281509{padding-top: 50px !important;}\"]<span style=\"color: #085ca9; font-size: 43px; line-height: 1.304347826086957em;\">Con Plata tienes el control\r\nde los gastos de tu empresa</span>[/vc_column_text][/vc_column][/vc_row][vc_row css_animation=\"\" row_type=\"row\" type=\"full_width\" text_align=\"center\" css=\".vc_custom_1460519024274{padding-top: 15px !important;padding-bottom: 15px !important;}\"][vc_column][vc_column_text el_class=\"innerTemplateTopMenu\"]<a id=\"perfilDeTebca\" href=\"#p8tabs\" rel=\"attachment wp-att-161\"><img class=\"alignnone size-full wp-image-161\" src=\"/wp-content/uploads/2016/04/Pagina-Internas-240222_03-4.png\" alt=\"Pagina-Internas-240222_03 (4)\" width=\"63\" height=\"50\" /> ¿Quiénes somos?</a>           <a id=\"dondeEstamos\" href=\"#p8tabs\" rel=\"attachment wp-att-162\"><img class=\"alignnone size-full wp-image-162\" src=\"/wp-content/uploads/2016/06/donde-estasmos.png\" alt=\"Pagina-Internas-240222_05 (2)\" width=\"48\" height=\"50\" />  Contáctenos</a>[/vc_column_text][/vc_column][/vc_row][vc_row css_animation=\"\" row_type=\"row\" type=\"grid\" text_align=\"left\" css=\".vc_custom_1466546965119{margin-right: -25% !important;margin-left: -25% !important;border-bottom-width: 170px !important;padding-top: 80px !important;padding-bottom: 63px !important;}\" el_id=\"p8tabs\"][vc_column][vc_tabs style=\"horizontal\"][vc_tab title=\"¿Quiénes somos?\" tab_id=\"68bdd577-fdae-92a14-bb2d\"][vc_row_inner row_type=\"row\" type=\"grid\" text_align=\"left\" css_animation=\"\"][vc_column_inner width=\"1/2\"][vc_column_text el_class=\"quienes-section\"]\r\n<h3 class=\"banner2\" style=\"color: #085ca9;\"><strong>¡CONOCE MÁS SOBRE TEBCA!</strong></h3>\r\nTebca es una Fintech especializada en la gestión, diseño, desarrollo e implementación de programas de pago electrónico. Aplicamos tecnologías para optimizar procesos de pagos y servicios para empresas y personas.\r\n\r\nSomos una empresa autorizados por la Superintendencia de Banca, Seguros y AFP para operar como Empresa Emisora de Dinero Electrónico\r\n\r\n<strong>Nuestra Misi<strong>ón</strong>:</strong>\r\nFacilitar los pagos y hacer que las empresas y personas tengan una mejor gestión financiera y ordenen su economía\r\n\r\n<strong>Nuestra V<strong>isi<strong>ón</strong></strong>:</strong>\r\nSer reconocidos como la empresa líder en la administración y gestión de programas prepago en el Perú[/vc_column_text][/vc_column_inner][vc_column_inner width=\"1/2\"][vc_single_image image=\"942\" img_size=\"large\" qode_css_animation=\"\"][/vc_column_inner][/vc_row_inner][/vc_tab][vc_tab title=\"Contáctenos\" tab_id=\"0880033b-3442-02a14-bb2d\"][vc_row_inner row_type=\"row\" type=\"grid\" text_align=\"left\" css_animation=\"\"][vc_column_inner width=\"1/2\"][vc_column_text]\r\n<h3 class=\"banner2\" style=\"color: #085ca9;\"><strong>CONTÁCTENOS</strong></h3>\r\n<p class=\"banner3text\"><strong>Teléfonos</strong>\r\nVentas e Información a empresas: 619-8900\r\nCentro de Atención las 24 horas: 619-8931</p>\r\n<p class=\"banner3text\"><strong>\r\nEmail</strong>\r\n<a href=\"mailto:ventas@tebca.com.pe\">ventas@tebca.com.pe</a></p>\r\n<p class=\"banner3text\"><strong>\r\nDirección</strong>\r\nAv. El Derby 250, Piso 15, Oficina 1501\r\nSantiago de Surco, Lima 33, Perú</p>\r\n[/vc_column_text][/vc_column_inner][vc_column_inner width=\"1/2\"][vc_single_image image=\"947\" img_size=\"large\" qode_css_animation=\"\"][/vc_column_inner][/vc_row_inner][/vc_tab][/vc_tabs][/vc_column][/vc_row]', 'Sobre Tebca', '', 'publish', 'closed', 'closed', '', 'sobre-tebca', '', '', '2021-09-23 15:56:41', '2021-09-23 20:56:41', '', 0, 'http://70.32.115.119/~provisbonusweb/?page_id=247', 2, 'page', '', 0);
INSERT INTO `wp_posts` (`ID`, `post_author`, `post_date`, `post_date_gmt`, `post_content`, `post_title`, `post_excerpt`, `post_status`, `comment_status`, `ping_status`, `post_password`, `post_name`, `to_ping`, `pinged`, `post_modified`, `post_modified_gmt`, `post_content_filtered`, `post_parent`, `guid`, `menu_order`, `post_type`, `post_mime_type`, `comment_count`) VALUES
(249, 3, '2016-04-12 07:52:28', '2016-04-12 07:52:28', '[vc_row css_animation=\"\" row_type=\"row\" type=\"grid\" text_align=\"left\" background_image=\"1474\" css=\".vc_custom_1482206418295{padding-top: 14px !important;padding-bottom: 73px !important;}\" el_class=\"full\"][vc_column el_class=\"black-btn\" css=\".vc_custom_1460386375532{margin-top: -50px !important;padding-top: 90px !important;padding-bottom: 100px !important;}\"][vc_column_text el_class=\"islider\" css=\".vc_custom_1480454740048{padding-top: 50px !important;}\"]\r\n<p style=\"text-align: right;\"><span style=\"color: white; font-size: 43px; line-height: 1.304347826086957em;\">Plata es la solución eficaz\r\npara el manejo de fondos</span></p>\r\n[/vc_column_text][/vc_column][/vc_row][vc_row css_animation=\"\" row_type=\"row\" type=\"full_width\" text_align=\"center\" css=\".vc_custom_1460519024274{padding-top: 15px !important;padding-bottom: 15px !important;}\"][vc_column offset=\"vc_hidden-sm vc_hidden-xs\"][vc_column_text el_class=\"innerTemplateTopMenu\"]<a id=\"programas\" class=\"tab-link\" href=\"#p8tabs\" rel=\"attachment wp-att-162\"><img class=\"alignnone size-full wp-image-162\" src=\"/wp-content/uploads/2016/06/emision-de-tarjetas-y-recargas.png\" alt=\"Pagina-Internas-240222_05 (2)\" width=\"48\" height=\"50\" /> Programas</a>     <a id=\"beneficios\" class=\"tab-link\" href=\"#p8tabs\" rel=\"attachment wp-att-162\"><img class=\"alignnone size-full wp-image-162\" src=\"/wp-content/uploads/2016/04/Pagina-Internas-240222_05-2.png\" alt=\"Pagina-Internas-240222_05 (2)\" width=\"48\" height=\"50\" /> Beneficios</a>     <a id=\"emision\" href=\"#emision-facturacion\" rel=\"attachment wp-att-165\"><img class=\"alignnone size-full wp-image-165\" src=\"http://platape.wpengine.com/wp-content/uploads/2016/06/servicios-en-linea.png\" alt=\"Pagina-Internas-240222_11\" width=\"36\" height=\"50\" /> Emisión y Recarga</a>     <a id=\"serviciosEnLinea\" class=\"tab-link\" href=\"#p8tabs\" rel=\"attachment wp-att-163\"><img class=\"alignnone size-full wp-image-163\" src=\"/wp-content/uploads/2016/04/Pagina-Internas-240222_07-2.png\" alt=\"Pagina-Internas-240222_07 (2)\" width=\"48\" height=\"50\" /> Servicios en Línea</a>     <a id=\"facturacion\" href=\"#emision-facturacion\"><img class=\"alignnone size-full wp-image-165\" src=\"https://stplatape.wpenginepowered.com/wp-content/uploads/2016/04/facturacion.png\" alt=\"Pagina-Internas-240222_11\" width=\"36\" height=\"50\" /> Facturación</a>     <a id=\"afiliacionLink\" href=\"#afiliacion\" rel=\"attachment wp-att-164\"><img class=\"alignnone size-full wp-image-164\" src=\"/wp-content/uploads/2016/04/Pagina-Internas-240222_09-2.png\" alt=\"Pagina-Internas-240222_09 (2)\" width=\"47\" height=\"50\" /> Contratación</a>     <a id=\"preguntaslink\" href=\"#Preguntas\" rel=\"attachment wp-att-165\"><img class=\"alignnone size-full wp-image-165\" src=\"/wp-content/uploads/2016/04/Pagina-Internas-240222_11.png\" alt=\"Pagina-Internas-240222_11\" width=\"36\" height=\"50\" /> Preguntas Frecuentes</a>[/vc_column_text][/vc_column][/vc_row][vc_row css_animation=\"\" row_type=\"row\" type=\"full_width\" text_align=\"center\" css=\".vc_custom_1460519024274{padding-top: 15px !important;padding-bottom: 15px !important;}\"][vc_column offset=\"vc_hidden-lg vc_hidden-md\"][vc_column_text el_class=\"innerTemplateTopMenu\"]<a id=\"programas\" class=\"tab-link\" href=\"#p8tabs\" rel=\"attachment wp-att-162\"><img class=\"alignnone size-full wp-image-162\" src=\"/wp-content/uploads/2016/06/emision-de-tarjetas-y-recargas.png\" alt=\"Pagina-Internas-240222_05 (2)\" width=\"48\" height=\"50\" /> Programas</a> <a id=\"beneficios\" class=\"tab-link\" style=\"margin-top: 10px;\" href=\"#p8tabs\" rel=\"attachment wp-att-162\"><img class=\"alignnone size-full wp-image-162\" src=\"/wp-content/uploads/2016/04/Pagina-Internas-240222_05-2.png\" alt=\"Pagina-Internas-240222_05 (2)\" width=\"48\" height=\"50\" /> Beneficios</a> <a id=\"emision\" href=\"#emision-facturacion\" rel=\"attachment wp-att-165\"><img class=\"alignnone size-full wp-image-165\" src=\"http://platape.wpengine.com/wp-content/uploads/2016/06/servicios-en-linea.png\" alt=\"Pagina-Internas-240222_11\" width=\"36\" height=\"50\" /> Emisión y Recarga</a>[/vc_column_text][/vc_column][/vc_row][vc_row css_animation=\"\" row_type=\"row\" type=\"full_width\" text_align=\"center\" css=\".vc_custom_1460519024274{padding-top: 15px !important;padding-bottom: 15px !important;}\"][vc_column offset=\"vc_hidden-lg vc_hidden-md\"][vc_column_text el_class=\"innerTemplateTopMenu\"]<a id=\"serviciosEnLinea\" class=\"tab-link\" href=\"#p8tabs\" rel=\"attachment wp-att-163\"><img class=\"alignnone size-full wp-image-163\" src=\"/wp-content/uploads/2016/04/Pagina-Internas-240222_07-2.png\" alt=\"Pagina-Internas-240222_07 (2)\" width=\"48\" height=\"50\" /> Servicios en Línea</a> <a id=\"facturacion\" style=\"margin-top: 10px;\" href=\"#emision-facturacion\"><img class=\"alignnone size-full wp-image-165\" src=\"https://stplatape.wpenginepowered.com/wp-content/uploads/2016/04/facturacion.png\" alt=\"Pagina-Internas-240222_11\" width=\"36\" height=\"50\" /> Facturación</a> <a id=\"afiliacionLink\" href=\"#afiliacion\" rel=\"attachment wp-att-164\"><img class=\"alignnone size-full wp-image-164\" src=\"/wp-content/uploads/2016/04/Pagina-Internas-240222_09-2.png\" alt=\"Pagina-Internas-240222_09 (2)\" width=\"47\" height=\"50\" /> Contratación</a>[/vc_column_text][/vc_column][/vc_row][vc_row css_animation=\"\" row_type=\"row\" type=\"full_width\" text_align=\"center\" css=\".vc_custom_1460519024274{padding-top: 15px !important;padding-bottom: 15px !important;}\"][vc_column offset=\"vc_hidden-lg vc_hidden-md\"][vc_column_text el_class=\"innerTemplateTopMenu\"]\r\n<p style=\"text-align: center;\"><a id=\"preguntaslink\" href=\"#Preguntas\" rel=\"attachment wp-att-165\"><img class=\"alignnone size-full wp-image-165\" src=\"/wp-content/uploads/2016/04/Pagina-Internas-240222_11.png\" alt=\"Pagina-Internas-240222_11\" width=\"36\" height=\"50\" /> Preguntas Frecuentes</a></p>\r\n[/vc_column_text][/vc_column][/vc_row][vc_row css_animation=\"\" row_type=\"row\" type=\"grid\" text_align=\"left\" background_color=\"#f2f3f2\" css=\".vc_custom_1460822286376{padding-top: 43px !important;padding-bottom: 43px !important;}\" el_class=\"full\"][vc_column width=\"1/3\"][vc_single_image image=\"271\" img_size=\"full\" alignment=\"center\" qode_css_animation=\"\" el_class=\"innerTemplateTopImage\"][vc_column_text el_class=\"blog-txt innerTemplateTopText\"]\r\n<h3 style=\"text-align: center; color: #085ca9;\">Agilidad</h3>\r\n&nbsp;\r\n<p style=\"text-align: center;\"> Procesamiento inmediato de la información y abono automático de los beneficios al trabajador</p>\r\n[/vc_column_text][/vc_column][vc_column width=\"1/3\"][vc_single_image image=\"270\" img_size=\"full\" alignment=\"center\" qode_css_animation=\"\" el_class=\"innerTemplateTopImage\"][vc_column_text el_class=\"blog-txt innerTemplateTopText\"]\r\n<h3 style=\"text-align: center; color: #085ca9;\">Seguridad</h3>\r\n&nbsp;\r\n<p style=\"text-align: center;\">Resguardamos la integridad y la privacidad de tu información</p>\r\n[/vc_column_text][/vc_column][vc_column width=\"1/3\"][vc_single_image image=\"272\" img_size=\"full\" alignment=\"center\" qode_css_animation=\"\" el_class=\"innerTemplateTopImage\"][vc_column_text el_class=\"blog-txt innerTemplateTopText\"]\r\n<h3 style=\"text-align: center; color: #085ca9;\">Acceso 7x24</h3>\r\n&nbsp;\r\n<p style=\"text-align: center;\">Plataforma disponible las 24 horas para emisión y recarga de cuentas/tarjetas</p>\r\n[/vc_column_text][/vc_column][/vc_row][vc_row css_animation=\"\" row_type=\"row\" type=\"grid\" text_align=\"left\" css=\".vc_custom_1466556271416{margin-right: -25% !important;margin-left: -25% !important;border-bottom-width: 170px !important;padding-top: 80px !important;padding-bottom: 63px !important;}\" el_id=\"p8tabs\"][vc_column][vc_tabs style=\"horizontal\"][vc_tab title=\"Programas\" tab_id=\"1477581906472-3-1\"][vc_row_inner row_type=\"row\" type=\"grid\" text_align=\"left\" css_animation=\"\"][vc_column_inner width=\"1/2\"][vc_column_text el_class=\"extra-space\"]\r\n<h3 class=\"banner2\" style=\"color: #085ca9;\">PROGRAMAS</h3>\r\nContamos con los mejores programas de acuerdo a sus necesidades.\r\n\r\nTe ofrecemos\r\n<ul>\r\n 	<li><a href=\"https://stplatape.wpenginepowered.com/sobre-tebca/programas-plata/\">Plata</a></li>\r\n 	<li><a href=\"https://stplatape.wpenginepowered.com/sobre-tebca/programas-plata-compras/\">Plata Compras</a></li>\r\n 	<li><a href=\"https://stplatape.wpenginepowered.com/sobre-tebca/programas-plata-gasolina/\">Plata Gasolina</a></li>\r\n</ul>\r\n[/vc_column_text][vc_empty_space][/vc_column_inner][vc_column_inner width=\"1/2\"][vc_single_image image=\"1313\" img_size=\"full\" alignment=\"center\" qode_css_animation=\"\"][/vc_column_inner][/vc_row_inner][/vc_tab][vc_tab title=\"Beneficios\" tab_id=\"0880033b-3442-06842-c166\"][vc_row_inner row_type=\"row\" type=\"grid\" text_align=\"left\" css_animation=\"\"][vc_column_inner width=\"1/2\"][vc_column_text el_class=\"extra-space\"]\r\n<h3 class=\"banner2\" style=\"color: #085ca9;\">BENEFICIOS PARA TU EMPRESA</h3>\r\n<ul>\r\n 	<li style=\"font-weight: 400;\"><span style=\"font-weight: 400;\">Reduce los procesos administrativos</span></li>\r\n 	<li style=\"font-weight: 400;\"><span style=\"font-weight: 400;\">Control y confidencialidad</span></li>\r\n 	<li style=\"font-weight: 400;\"><span style=\"font-weight: 400;\">Plataforma de autogestión. Conexión empresas online para emitir y recargar tarjetas desde la página web <a href=\"http://platape.wpengine.com\">platape.wpengine.com</a></span></li>\r\n 	<li style=\"font-weight: 400;\"><span style=\"font-weight: 400;\">Reportes de gestión. Obtener información sobre las operaciones realizadas y gestionar en línea la emisión de reportes en Excel, PDF y gráficos que facilitan auditorías/controles de los gastos realizados</span></li>\r\n 	<li style=\"font-weight: 400;\"><span style=\"font-weight: 400;\">Servicio de Post-Venta</span></li>\r\n</ul>\r\n[/vc_column_text][vc_empty_space][/vc_column_inner][vc_column_inner width=\"1/2\"][vc_single_image image=\"934\" img_size=\"full\" alignment=\"center\" qode_css_animation=\"\"][/vc_column_inner][/vc_row_inner][/vc_tab][vc_tab title=\"Servicios en línea\" tab_id=\"1460380846457-2-66842-c166\"][vc_row_inner row_type=\"row\" type=\"grid\" text_align=\"left\" css_animation=\"\"][vc_column_inner width=\"1/2\"][vc_column_text el_class=\"extra-space\"]\r\n<h3 class=\"banner2\" style=\"color: #085ca9;\">SERVICIOS EN LÍNEA</h3>\r\n<strong>Conexión Empresas Online\r\n</strong><span style=\"font-weight: 400;\">A cualquier hora y desde cualquier lugar, el personal autorizado de tu empresa cuenta con acceso a nuestro sistema Conexión Empresas Online, para realizar las siguientes operaciones:</span>\r\n\r\n&nbsp;\r\n<ul>\r\n 	<li style=\"font-weight: 400;\"><span style=\"font-weight: 400;\">Enviar lotes de emisión y recarga de cuentas/tarjeta</span></li>\r\n 	<li style=\"font-weight: 400;\"><span style=\"font-weight: 400;\">Autorizar y/o eliminar un lote</span></li>\r\n 	<li style=\"font-weight: 400;\"><span style=\"font-weight: 400;\">Consultar el histórico de lotes de emisión y recarga autorizados</span></li>\r\n 	<li style=\"font-weight: 400;\"><span style=\"font-weight: 400;\">Generar Órdenes de Servicio para identificar los pagos a realizar</span></li>\r\n 	<li style=\"font-weight: 400;\"><span style=\"font-weight: 400;\">Registrar todas las operaciones realizadas para consultas posteriores, auditorías o reportes requeridos por el Ministerio de Trabajo u otra institución</span></li>\r\n</ul>\r\n[/vc_column_text][vc_empty_space][/vc_column_inner][vc_column_inner width=\"1/2\"][vc_single_image image=\"1238\" img_size=\"large\" qode_css_animation=\"\"][/vc_column_inner][/vc_row_inner][/vc_tab][/vc_tabs][/vc_column][/vc_row][vc_row css_animation=\"\" row_type=\"row\" type=\"grid\" text_align=\"left\" background_image=\"1365\" css=\".vc_custom_1478789884784{padding-top: 60px !important;padding-bottom: 60px !important;}\" el_class=\"full\" el_id=\"afiliacion\"][vc_column][vc_column_text el_class=\"black-btn\"]\r\n<h2 style=\"color: #085ca9;\"><span style=\"color: #ffffff;\"><strong>CONTRATACIÓN</strong></span></h2>\r\n&nbsp;\r\n<p class=\"bannertext2\">El proceso de afiliación es muy sencillo:\r\nLlenar la ficha de cliente, aprobar la propuesta de servicio y firmar el contrato marco</p>\r\n[/vc_column_text][/vc_column][/vc_row][vc_row css_animation=\"\" row_type=\"row\" type=\"grid\" text_align=\"left\" background_color=\"#f2f3f2\" el_id=\"emision-facturacion\" css=\".vc_custom_1481837613958{padding-top: 45px !important;}\" el_class=\"full\"][vc_column][vc_tabs style=\"horizontal\"][vc_tab title=\"Emisión y Recarga\" tab_id=\"39b3d576-22e8-0\"][vc_row_inner row_type=\"row\" type=\"grid\" text_align=\"left\" css_animation=\"\"][vc_column_inner][vc_column_text]\r\n<h3 style=\"text-align: left;\"><strong><span style=\"color: #005baa;\"><span style=\"font-size: 28px;\">EMISIÓN DE </span><span style=\"font-size: 28px; line-height: 42px;\">PLÁSTICOS</span><span style=\"font-size: 28px;\"> Y RECARGAS</span></span></strong></h3>\r\n<h4 style=\"text-align: center;\"></h4>\r\n[/vc_column_text][vc_empty_space][/vc_column_inner][/vc_row_inner][vc_row_inner row_type=\"row\" type=\"grid\" text_align=\"left\" css_animation=\"\"][vc_column_inner width=\"1/2\"][vc_column_text el_class=\"extra-space\"]\r\n<h3>Solicitud de emisión de tarjetas</h3>\r\n<ul>\r\n 	<li>La solicitud debe ser enviada a través de la opción Carga de Lotes del sistema <a href=\"https://online.novopayment.net/empresas/Pe/login\">Conexión Empresas Online</a>, siguiendo los pasos descritos en el instructivo para la generación del archivo a ser enviado</li>\r\n 	<li>Tebca enviará las tarjetas a tu empresa, una vez generadas (3 días Lima y 5 días Provincia), junto con el comprobante de recepción</li>\r\n 	<li>Una vez que Tebca tenga en su poder los acuses de recibo, tu empresa podrá solicitar la carga de las mismas</li>\r\n</ul>\r\n[/vc_column_text][vc_empty_space][/vc_column_inner][vc_column_inner width=\"1/2\"][vc_column_text el_class=\"extra-space\"]\r\n<h3>Solicitud de carga y recarga de tarjetas</h3>\r\n<ul>\r\n 	<li style=\"font-weight: 400;\"><span style=\"font-weight: 400;\">Debe ser enviada a través de la opción Carga de Lotes del sistema </span><a href=\"https://online.novopayment.net/empresas/Pe/login\"><span style=\"font-weight: 400;\">Conexión Empresas Online</span></a><span style=\"font-weight: 400;\">, siguiendo los pasos descritos en el instructivo para la generación del archivo a ser enviado</span></li>\r\n 	<li style=\"font-weight: 400;\"><span style=\"font-weight: 400;\">Tebca efectuará la carga en un máximo de 24 horas, luego de tener los fondos disponibles</span></li>\r\n</ul>\r\n[/vc_column_text][/vc_column_inner][/vc_row_inner][/vc_tab][vc_tab title=\"Facturación\" tab_id=\"2e749f17-76b8-0\"][vc_row_inner row_type=\"row\" type=\"grid\" text_align=\"left\" css_animation=\"\"][vc_column_inner][vc_column_text]\r\n<h3 style=\"text-align: left;\"><span style=\"color: #005baa; font-size: 28px;\"><strong>FACTURACIÓN</strong></span></h3>\r\n<h4 style=\"text-align: center;\"></h4>\r\n[/vc_column_text][vc_empty_space][vc_column_text]La empresa deberá efectuar el pago por el importe correspondiente al Documento de Cobranza (Orden de Servicio) considerando el monto de la recarga y la comisión administrativa generada.\r\n\r\nPara efectos de la detracción del Impuesto General a las Ventas – I.G.V., el 10% del monto de las comisiones administrativas (incluyendo el I.G.V.) deberá ser abonado en la cuenta de Tebca en el Banco de la Nación Cuenta Corriente N°00005184592.\r\n\r\nLa empresa podrá realizar el abono correspondiente a través de las siguientes cuentas:\r\n\r\n&nbsp;\r\n\r\nInterbank:\r\n<ul>\r\n 	<li>• Depósito en Cuenta Corriente en Nuevos Soles N° 200-3000423872 a nombre Servitebca Perú</li>\r\n 	<li>Transferencia Interbancaria a la Cuenta Corriente CCI 003-200-003000423872-38</li>\r\n</ul>\r\n&nbsp;\r\n\r\nBCP:\r\n<ul>\r\n 	<li>Depósito en Cuenta Corriente en Nuevos Soles N° 193-1872433-0-63</li>\r\n 	<li>Transferencia Interbancaria a la Cuenta Corriente CCI 002-193-001872433063-16</li>\r\n</ul>\r\n&nbsp;\r\n\r\nUna vez enviada la constancia de abono al buzón <a href=\"mailto:autorizaciones@tebca.com.pe\">autorizaciones@tebca.com.pe</a> y se verifique que los fondos se encuentren disponibles en la cuenta de Tebca, las recargas de tarjetas se realizarán según el horario Indicado:\r\n<ul>\r\n 	<li>Recepción de constancias de abono hasta las 11:30 am, la recarga estará disponible a las 3:00pm</li>\r\n 	<li>Recepción de constancias de abono hasta las 4:30 pm, la recarga estará disponible al día siguiente. (Considerar que los viernes el horario de recepción es hasta las 4:00pm)</li>\r\n</ul>\r\n[/vc_column_text][vc_empty_space][/vc_column_inner][/vc_row_inner][/vc_tab][/vc_tabs][vc_empty_space][/vc_column][/vc_row][vc_row css_animation=\"\" row_type=\"row\" type=\"full_width\" text_align=\"left\" el_id=\"Preguntas\" css=\".vc_custom_1466784100890{padding-top: 45px !important;}\"][vc_column][vc_column_text]\r\n<h3 style=\"text-align: center;\"><strong><span style=\"color: #005baa; font-size: 28px;\"><strong>PREGUNTAS FRECUENTES</strong></span></strong></h3>\r\n<h4 style=\"text-align: center;\"></h4>\r\n[/vc_column_text][vc_empty_space][/vc_column][/vc_row][vc_row css_animation=\"\" row_type=\"row\" type=\"full_width\" text_align=\"left\" css=\".vc_custom_1466784131815{padding-top: 25px !important;padding-bottom: 44px !important;}\"][vc_column width=\"1/2\" el_class=\"item1\"][vc_accordion active_tab=\"1\" collapsible=\"yes\" style=\"accordion\"][vc_accordion_tab title=\"¿Qué requisitos deben cumplir las empresas para afiliarse al servicio?\" icon=\"\"][vc_column_text]\r\n<ul>\r\n 	<li>Enviar la ficha de registro del cliente.</li>\r\n 	<li>Firmar el contrato Marco de Servicios.</li>\r\n</ul>\r\n&nbsp;\r\n\r\nAnexar:\r\n<ul>\r\n 	<li>Documento constitutivo de la empresa y sus reformas si las hubiere.</li>\r\n 	<li>Vigencia de Poderes de los representantes, emitida por Registros Públicos con una antigüedad no mayor a quince días hábiles.</li>\r\n 	<li>Documento adicional, si fuere necesario, que acredite la facultad de las personas que representarán a la empresa en la celebración del contrato.</li>\r\n 	<li>Fotocopia del Documento de identidad vigente del(los) representante(s) de su empresa.</li>\r\n 	<li>Copia simple de la Ficha RUC de la empresa.</li>\r\n</ul>\r\n&nbsp;\r\n\r\nTodos estos requisitos deberán ser presentados para poder hacer efectivas las instrucciones de abono de beneficios a las tarjetas emitidas por la empresa.[/vc_column_text][/vc_accordion_tab][vc_accordion_tab title=\"¿Cuáles son los mecanismos de pago a Tebca para cubrir los costos del servicio?\" icon=\"\"][vc_column_text]<span style=\"font-weight: 400;\">Consultar sección facturación</span>[/vc_column_text][/vc_accordion_tab][vc_accordion_tab title=\"¿La facturación está sujeta al pago del Impuesto General a las Ventas (IGV)?\" icon=\"\"][vc_column_text]Sí, sólo la comisión de servicio, no el monto correspondiente a abonos.[/vc_column_text][/vc_accordion_tab][/vc_accordion][/vc_column][vc_column width=\"1/2\"][vc_accordion active_tab=\"false\" collapsible=\"yes\" style=\"accordion\"][vc_accordion_tab title=\"¿Qué es el Sistema Conexión Empresas Online?\" icon=\"\"][vc_column_text]Tebca ofrece a sus clientes el <span style=\"font-weight: 400;\">Conexión Empresas Online</span> que permite enviar instrucciones a favor de sus empleados y/o beneficiarios vía internet. Mediante este sistema las empresas o instituciones – a través de funcionarios que ellas designen – pueden solicitar directamente la emisión de sus tarjetas electrónicas, la recarga de los beneficios para sus trabajadores y además obtienen en línea tanto la Orden de Servicio para efectuar los depósitos o transferencias a Tebca, como los datos de la factura definitiva. Esta plataforma se encuentra disponible a través de la página web <a href=\"http://www.platape.wpengine.com\">www.platape.wpengine.com</a>, a las 24 horas del día, todos los días del año.\r\n\r\n&nbsp;\r\n\r\nTebca hace entrega a las empresas del Instructivo que especifica todos los pasos que la empresa debe seguir para la instalación y funcionamiento de este Sistema, en el que se detalla la siguiente información:\r\n<ul>\r\n 	<li>Cómo acceder al Sistema</li>\r\n 	<li>Cómo crear archivos de emisión o recarga de tarjetas</li>\r\n 	<li>Autorizar un lote</li>\r\n 	<li>Consultar lotes enviados</li>\r\n 	<li>Anular un lote enviado</li>\r\n 	<li>Cambio de clave de acceso</li>\r\n</ul>\r\n[/vc_column_text][/vc_accordion_tab][vc_accordion_tab title=\"¿Cuáles son los beneficios del Conexión Online para las empresas?\" icon=\"\"][vc_column_text]\r\n<ul>\r\n 	<li>Acceso vía Internet a la plataforma electrónica de Tebca.</li>\r\n 	<li>Sistema inteligente que interactúa con la base de datos de la empresa, evitando así errores en la emisión o carga de las tarjetas.</li>\r\n 	<li>Sistema compatible con cualquier administrador de nóminas.</li>\r\n 	<li>Sistema multiusuario que permite múltiples niveles de seguridad.</li>\r\n 	<li>Conexión directa para envío de lotes de emisión y recarga de plásticos.</li>\r\n 	<li>El sistema permite autorizar, consultar y/o eliminar los lotes notificando su respectivo estatus.</li>\r\n 	<li>Permite autogestionar requerimientos de auditoría de archivos y emisión de reportes.</li>\r\n</ul>\r\n[/vc_column_text][/vc_accordion_tab][vc_accordion_tab title=\"¿Quiénes son las personas autorizadas para operar el sistema Conexión Empresas Online?\" icon=\"\"][vc_column_text]El Sistema permite crear hasta cinco usuarios, cada uno de los cuales contará con su respectiva clave secreta (personal e intransferible). Los procesos que se cumplen en Tebca Online tienen dos niveles, uno para la carga de la información y el otro para autorizarla. La empresa decidirá si solo una persona hará los dos pasos o lo harán dos distintas, y en ese último caso deberá solicitar una clave adicional para el segundo.[/vc_column_text][/vc_accordion_tab][/vc_accordion][/vc_column][/vc_row][vc_row css_animation=\"\" row_type=\"row\" type=\"full_width\" text_align=\"left\"][vc_column][vc_empty_space height=\"100px\"][/vc_column][/vc_row]', 'Empresas', '', 'publish', 'closed', 'closed', '', 'empresas', '', '', '2021-08-21 13:52:23', '2021-08-21 18:52:23', '', 0, 'http://70.32.115.119/~provisbonusweb/?page_id=249', 3, 'page', '', 0),
(252, 3, '2016-04-12 07:53:33', '2016-04-12 07:53:33', '[vc_row css_animation=\"\" row_type=\"row\" type=\"grid\" text_align=\"left\" background_image=\"1375\" css=\".vc_custom_1482206441802{padding-top: 14px !important;padding-bottom: 73px !important;}\" el_class=\"full\"][vc_column el_class=\"black-btn\" css=\".vc_custom_1460386375532{margin-top: -50px !important;padding-top: 90px !important;padding-bottom: 100px !important;}\"][vc_column_text el_class=\"islider\" css=\".vc_custom_1480439278914{padding-top: 50px !important;}\"]<span style=\"color: #085ca9; font-size: 43px; line-height: 1.304347826086957em;\">Con Plata accede a\r\nmiles de establecimientos</span>[/vc_column_text][/vc_column][/vc_row][vc_row css_animation=\"\" row_type=\"row\" type=\"full_width\" text_align=\"center\" css=\".vc_custom_1460519024274{padding-top: 15px !important;padding-bottom: 15px !important;}\"][vc_column][vc_column_text el_class=\"innerTemplateTopMenu\"]<a id=\"tarjetaProvis3\" href=\"#p8tabs\" rel=\"attachment wp-att-161\"><img class=\"alignnone size-full wp-image-161\" src=\"https://stplatape.wpenginepowered.com/wp-content/uploads/2016/04/Pagina-Internas-240222_03-4.png\" alt=\"Pagina-Internas-240222_03 (4)\" width=\"63\" height=\"50\" />   Programas</a>         <a id=\"canalesDeAcceso\" href=\"#p8tabs\" rel=\"attachment wp-att-163\"><img class=\"alignnone size-full wp-image-163\" src=\"https://stplatape.wpenginepowered.com/wp-content/uploads/2016/04/Pagina-Internas-240222_07-2.png\" alt=\"Pagina-Internas-240222_07 (2)\" width=\"48\" height=\"50\" />   Canales de acceso</a>          <a id=\"reposiciones\" href=\"#p8tabs\" rel=\"attachment wp-att-163\"><img class=\"alignnone size-full wp-image-163\" src=\"http://platape.wpengine.com/wp-content/uploads/2016/06/perfil-tebca.png\" width=\"48\" height=\"50\" />   Reposiciones</a>          <a id=\"faqLink\" href=\"#faq\" rel=\"attachment wp-att-165\"><img class=\"alignnone size-full wp-image-165\" src=\"https://stplatape.wpenginepowered.com/wp-content/uploads/2016/04/Pagina-Internas-240222_11.png\" alt=\"Pagina-Internas-240222_11\" width=\"36\" height=\"50\" /> Preguntas frecuentes</a>[/vc_column_text][/vc_column][/vc_row][vc_row css_animation=\"\" row_type=\"row\" type=\"grid\" text_align=\"left\" background_color=\"#f2f3f2\" css=\".vc_custom_1460822286376{padding-top: 43px !important;padding-bottom: 43px !important;}\" el_class=\"full\"][vc_column width=\"1/3\"][vc_single_image image=\"270\" img_size=\"full\" alignment=\"center\" qode_css_animation=\"\" el_class=\"innerTemplateTopImage\"][vc_column_text el_class=\"blog-txt innerTemplateTopText\"]\r\n<h3 style=\"text-align: center; color: #085ca9;\"><strong>Seguridad</strong></h3>\r\n&nbsp;\r\n<p style=\"text-align: center;\">Usa tu clave secreta para mayor seguridad y evita los riesgos asociados al manejo de efectivo</p>\r\n[/vc_column_text][/vc_column][vc_column width=\"1/3\"][vc_single_image image=\"271\" img_size=\"full\" alignment=\"center\" qode_css_animation=\"\" el_class=\"innerTemplateTopImage\"][vc_column_text el_class=\"blog-txt innerTemplateTopText\"]\r\n<h3 style=\"text-align: center; color: #085ca9;\"><strong>Comodidad</strong></h3>\r\n&nbsp;\r\n<p style=\"text-align: center;\">Acceso de Lunes a Domingo a tus consultas de saldo y movimientos a través de nuestros canales de acceso</p>\r\n[/vc_column_text][/vc_column][vc_column width=\"1/3\"][vc_single_image image=\"272\" img_size=\"full\" alignment=\"center\" qode_css_animation=\"\" el_class=\"innerTemplateTopImage\"][vc_column_text el_class=\"blog-txt innerTemplateTopText\"]\r\n<h3 style=\"text-align: center; color: #085ca9;\"><strong>Agilidad</strong></h3>\r\n&nbsp;\r\n<p style=\"text-align: center;\">Tus beneficios son abonados inmediatamente sin tener que esperar cupones o vales de papel</p>\r\n[/vc_column_text][/vc_column][/vc_row][vc_row css_animation=\"\" row_type=\"row\" type=\"grid\" text_align=\"left\" css=\".vc_custom_1466451905157{border-bottom-width: 170px !important;padding-top: 80px !important;padding-bottom: 63px !important;}\" el_class=\"full\" el_id=\"p8tabs\"][vc_column][vc_tabs style=\"horizontal\"][vc_tab title=\"Programas\" tab_id=\"68bdd577-fdae-91a5d-0284\"][vc_row_inner row_type=\"row\" type=\"grid\" text_align=\"left\" css_animation=\"\"][vc_column_inner width=\"1/2\"][vc_column_text css=\".vc_custom_1484855745573{background-image: url(https://stplatape.wpenginepowered.com/wp-content/uploads/2016/04/Imagen_Colaboradores_SobreProvisv2.png?id=890) !important;}\" el_class=\"extra-space\"]\r\n<h3 class=\"banner2\" style=\"color: #085ca9;\">PROGRAMAS</h3>\r\nConoce las características de nuestros productos\r\n<ul>\r\n 	<li><a href=\"/sobre-tebca/programas-personas-plata/\">Plata</a></li>\r\n 	<li><a href=\"/sobre-tebca/programas-personas-plata-compras/\">Plata Compras</a></li>\r\n 	<li><a href=\"https://stplatape.wpenginepowered.com/sobre-tebca/programas-personas/#plata-compras\">Plata Gasolina</a></li>\r\n</ul>\r\n[/vc_column_text][/vc_column_inner][vc_column_inner width=\"1/2\"][vc_single_image image=\"1313\" img_size=\"full\" alignment=\"center\" qode_css_animation=\"\"][/vc_column_inner][/vc_row_inner][/vc_tab][vc_tab title=\"Canales de acceso\" tab_id=\"1460380846457-2-61a5d-0284\"][vc_row_inner row_type=\"row\" type=\"grid\" text_align=\"left\" css_animation=\"\"][vc_column_inner width=\"1/2\"][vc_column_text el_class=\"canales-section\"]\r\n<h3 class=\"banner2\" style=\"color: #085ca9;\">CANALES DE ACCESO</h3>\r\n<strong>Centro de Atención al Cliente</strong>\r\nTeléfono (01) 619-8931\r\nDisponible de Lunes a Domingo de 6:00 a.m. a 10:00 p.m.\r\n\r\n<strong>IVR</strong>\r\nTeléfono (01) 619-8931\r\nMarca la opción 1 para consultas de saldo y movimientos.\r\n\r\n<strong>stplatape.wpenginepowered.com</strong>\r\nPara consultar saldo y movimientos entra a Conexión Personas Online.\r\n\r\n<strong>Email</strong>\r\nEscríbenos a <a href=\"mailto:reposiciones@tebca.com.pe\">reposiciones@tebca.com.pe</a> para solicitar la reposición de la tarjeta y/o clave.\r\n\r\n<strong>App Móvil</strong>\r\nDescarga la App Tebca Acceso Móvil en las tiendas de aplicaciones: App Store (iOS) y Play Store (Android)[/vc_column_text][/vc_column_inner][vc_column_inner width=\"1/2\"][vc_single_image image=\"1871\" img_size=\"large\" qode_css_animation=\"\"][/vc_column_inner][/vc_row_inner][/vc_tab][vc_tab title=\"Reposiciones\" tab_id=\"1478629821850-2-3\"][vc_row_inner row_type=\"row\" type=\"grid\" text_align=\"left\" css_animation=\"\"][vc_column_inner width=\"1/2\"][vc_column_text]\r\n<h3 class=\"banner2\" style=\"color: #085ca9;\">REPOSICIONES</h3>\r\nPara solicitar la reposición de la tarjeta, escríbenos a <a href=\"mailto:reposiciones@tebca.com.pe\">reposiciones@tebca.com.pe</a> o comunícate al Centro de Atención al Cliente al (511) 619-8930.\r\n\r\n&nbsp;\r\n\r\nLos tiempos de entrega son los siguientes previa confirmación de los datos y del pago:\r\n<ul>\r\n 	<li>Lima: 5 días útiles</li>\r\n 	<li>Provincia: 10 días útiles</li>\r\n</ul>\r\n[/vc_column_text][/vc_column_inner][vc_column_inner width=\"1/2\"][vc_single_image image=\"1694\" img_size=\"full\" alignment=\"center\" qode_css_animation=\"\"][/vc_column_inner][/vc_row_inner][/vc_tab][/vc_tabs][vc_separator type=\"normal\"][/vc_column][/vc_row][vc_row css_animation=\"\" row_type=\"row\" type=\"full_width\" text_align=\"left\" el_id=\"faq\"][vc_column][vc_column_text]\r\n<h3 style=\"text-align: center;\"><span style=\"color: #085ca9;\"><strong><span style=\"font-size: 28px;\">PREGUNTAS FRECUENTES</span></strong></span></h3>\r\n<h4 style=\"text-align: center;\"></h4>\r\n[/vc_column_text][/vc_column][/vc_row][vc_row css_animation=\"\" row_type=\"row\" type=\"grid\" text_align=\"left\" css=\".vc_custom_1460523725034{padding-top: 64px !important;padding-bottom: 44px !important;}\"][vc_column width=\"1/2\" el_class=\"item1\"][vc_accordion active_tab=\"1\" collapsible=\"yes\" style=\"accordion\"][vc_accordion_tab title=\"¿Cuáles son las características físicas de nuestras Tarjetas?\" icon=\"\"][vc_column_text]\r\n<ul>\r\n 	<li>Es una tarjeta que cuenta con un número compuesto por 16 dígitos, fecha de vencimiento y logotipo de MasterCard o Visa. La tarjeta puede llevar o no el nombre del tarjetahabiente y el de la empresa, es decir, el texto puede ser grabado de acuerdo a las instrucciones que indique la empresa.</li>\r\n 	<li>En el reverso lleva una banda magnética y un panel de firma.</li>\r\n 	<li>Las tarjetas Plata Compras y Plata Gasolina son de uso exclusivo en el territorio Peruano y la Tarjeta Plata puede usarse a nivel internacional</li>\r\n</ul>\r\n[/vc_column_text][/vc_accordion_tab][vc_accordion_tab title=\"¿Quién recarga la tarjeta?\" icon=\"\"][vc_column_text]La tarjeta solo puede ser recargada por la empresa, es esta quien define el monto y la frecuencia de la recarga. Los abonos realizados por la empresa se verán registrados en los movimientos de la tarjeta.[/vc_column_text][/vc_accordion_tab][vc_accordion_tab title=\"Además de las recargas que recibe de la empresa, ¿el usuario puede hacer abonos directamente?\" icon=\"\"][vc_column_text]No, solo la empresa está autorizada para realizar abonos en estas tarjetas.[/vc_column_text][/vc_accordion_tab][vc_accordion_tab title=\"¿Qué operaciones puedes realizar con tus Tarjetas?\" icon=\"\"][vc_column_text]Nuestras tarjetas permiten al usuario realizar las siguientes operaciones:\r\n<ul>\r\n 	<li data-listid=\"10\" data-aria-posinset=\"1\" data-aria-level=\"1\">Compras y consumos en miles de establecimientos afiliados a MasterCard y Visa.</li>\r\n 	<li data-listid=\"10\" data-aria-posinset=\"2\" data-aria-level=\"1\">En el caso de la Tarjeta Plata Gasolina esta solo puede ser utilizada para consumos en estaciones de servicio de combustibles</li>\r\n 	<li data-listid=\"10\" data-aria-posinset=\"3\" data-aria-level=\"1\">Retiro en efectivo: este tipo de operaciones solo está disponible para las Tarjeta Plata con retiro.</li>\r\n</ul>\r\n[/vc_column_text][/vc_accordion_tab][vc_accordion_tab title=\"¿Cómo realizo una compra en los establecimientos afiliados?\" icon=\"\"][vc_column_text]Es muy sencillo, sólo debes seguir los siguientes pasos:\r\n<ul>\r\n 	<li data-listid=\"8\" data-aria-posinset=\"1\" data-aria-level=\"1\">Al pagar por tus compras y consumos, presenta la tarjeta al encargado del establecimiento, este la deslizará por el terminal POS y digitará el monto del consumo.</li>\r\n 	<li data-listid=\"8\" data-aria-posinset=\"2\" data-aria-level=\"1\">Digita tu clave secreta (la que vino impresa en la carta que recibiste con la Tarjeta). Recuerda no permitir que terceros tengan acceso a tu clave.</li>\r\n 	<li data-listid=\"8\" data-aria-posinset=\"3\" data-aria-level=\"1\">El valor de tu compra será debitado automáticamente de tu tarjeta.</li>\r\n 	<li data-listid=\"8\" data-aria-posinset=\"4\" data-aria-level=\"1\">Reclama tu comprobante como constancia.</li>\r\n 	<li data-listid=\"8\" data-aria-posinset=\"5\" data-aria-level=\"1\">Recuerda que toda transacción efectuada con la tarjeta y clave secreta será válida y por tanto, se considerará efectuada por el titular de la Tarjeta.</li>\r\n 	<li data-listid=\"8\" data-aria-posinset=\"6\" data-aria-level=\"1\">En el voucher de tu compra, podrás verificar tu saldo disponible, posterior al último consumo realizado.</li>\r\n</ul>\r\n[/vc_column_text][/vc_accordion_tab][vc_accordion_tab title=\"¿Cómo obtengo mi clave secreta?\" icon=\"\"][vc_column_text]<span class=\"TextRun SCX115043496\" lang=\"ES-PE\" xml:lang=\"ES-PE\"><span class=\"NormalTextRun SCX115043496\">La </span></span><span class=\"TextRun SCX115043496\" lang=\"ES-PE\" xml:lang=\"ES-PE\"><span class=\"NormalTextRun SCX115043496\">clave s</span></span><span class=\"TextRun SCX115043496\" lang=\"ES-PE\" xml:lang=\"ES-PE\"><span class=\"NormalTextRun SCX115043496\">ecreta para realizar consumos</span></span><span class=\"TextRun SCX115043496\" lang=\"ES-PE\" xml:lang=\"ES-PE\"><span class=\"NormalTextRun SCX115043496\">, </span></span><span class=\"TextRun SCX115043496\" lang=\"ES-PE\" xml:lang=\"ES-PE\"><span class=\"NormalTextRun SCX115043496\">se encuentra en la carta de bienvenida </span></span><span class=\"TextRun SCX115043496\" lang=\"ES-PE\" xml:lang=\"ES-PE\"><span class=\"NormalTextRun SCX115043496\">con la que recibiste tu</span></span><span class=\"TextRun SCX115043496\" lang=\"ES-PE\" xml:lang=\"ES-PE\"><span class=\"NormalTextRun SCX115043496\"> Tarjeta. Para realizar el cambio de clave, comunícate al 01 619-8931 opción 3 </span></span>[/vc_column_text][/vc_accordion_tab][vc_accordion_tab title=\"¿Cómo obtienen los tarjetahabientes información sobre el saldo o movimientos de su tarjeta?\" icon=\"\"][vc_column_text]Podrás tener la información de tu saldo y movimientos a través de:\r\n<ul>\r\n 	<li data-listid=\"15\" data-aria-posinset=\"1\" data-aria-level=\"1\"><a href=\"https://stplatape.wpenginepowered.com/\">www.stplatape.wpenginepowered.com</a>, ingresa a Conexión Online/ Conexión Personas, si estas registrado digita tu usuario y clave, podrás obtener el detalle de todas tus operaciones realizadas con la tarjeta.</li>\r\n 	<li data-listid=\"15\" data-aria-posinset=\"2\" data-aria-level=\"1\">Descargar la App Servitebca, acceso móvil en las tiendas de aplicaciones: Google Play (Android), App Store (iPhone), App World (BlackBerry).</li>\r\n 	<li data-listid=\"15\" data-aria-posinset=\"3\" data-aria-level=\"1\">Llamar a nuestro Centro de Atención al Cliente 0801-00333 o 619-8931, servicio que se encuentra disponible las 24 horas.</li>\r\n</ul>\r\n[/vc_column_text][/vc_accordion_tab][/vc_accordion][/vc_column][vc_column width=\"1/2\"][vc_accordion active_tab=\"false\" collapsible=\"yes\" style=\"accordion\"][vc_accordion_tab title=\"¿Cómo accedo a la página web de Plata?\" icon=\"\"][vc_column_text]\r\n<ul>\r\n 	<li data-listid=\"18\" data-aria-posinset=\"1\" data-aria-level=\"1\">Al ingresar a la página web <a href=\"http://www.platape.wpengine.com/\">www.platape.wpengine.com</a> ingresa a Conexión Online, luego a Conexión Personas, si ingresas por primera vez debes registrarte.</li>\r\n 	<li data-listid=\"18\" data-aria-posinset=\"2\" data-aria-level=\"1\">Para registrarte necesitas los siguientes datos: país, número de la tarjeta, número de DNI y tu clave de 4 dígitos que aparece en la carta de bienvenida. Acepta las condiciones de uso y elige el botón de continuar.</li>\r\n 	<li data-listid=\"18\" data-aria-posinset=\"3\" data-aria-level=\"1\">Para acceder a tus cuentas el sistema te pedirá que generes un usuario y una nueva clave, esta debe cumplir con los requisitos indicados.</li>\r\n</ul>\r\n[/vc_column_text][/vc_accordion_tab][vc_accordion_tab title=\"¿Cuál es el procedimiento para presentar un reclamo?\" icon=\"\"][vc_column_text]\r\n<ul>\r\n 	<li data-listid=\"17\" data-aria-posinset=\"1\" data-aria-level=\"1\">El reclamo debe ser presentado sólo por el beneficiario o tarjetahabiente.</li>\r\n 	<li data-listid=\"17\" data-aria-posinset=\"2\" data-aria-level=\"1\">Es importante tomar en cuenta que el reclamo debe ser presentado antes que transcurran treinta (30) días desde la fecha de la transacción de consumo materia de reclamo.</li>\r\n 	<li data-listid=\"17\" data-aria-posinset=\"3\" data-aria-level=\"1\">El tarjetahabiente podrá comunicarse con nuestro Centro de Atención al Cliente 0801-00333 o 619-8931.</li>\r\n 	<li data-listid=\"17\" data-aria-posinset=\"4\" data-aria-level=\"1\">Una vez recibido el reclamo, se emitirá respuesta en un plazo máximo de quince (15) días hábiles contados a partir del día siguiente de presentado el reclamo. Dependiendo de la naturaleza del reclamo, se podrá solicitar información adicional.</li>\r\n</ul>\r\nPara conocer el procedimiento a detalle podrás acceder a la sección <a href=\"http://platape.wpengine.com/procedimiento-para-la-atencion-de-reclamos-y-solicitudes/\"><b>Procedimiento Para la Atención de Reclamos y Solicitudes </b> </a>[/vc_column_text][/vc_accordion_tab][vc_accordion_tab title=\"Si pierdo la tarjeta o me la roban, ¿pierdo el saldo?\" icon=\"\"][vc_column_text]<span class=\"TextRun Highlight SCX111949552\" lang=\"ES-PE\" xml:lang=\"ES-PE\"><span class=\"NormalTextRun SCX111949552\">No</span></span><span class=\"TextRun Highlight SCX111949552\" lang=\"ES-PE\" xml:lang=\"ES-PE\"><span class=\"NormalTextRun SCX111949552\">, el saldo no se pierde</span></span><span class=\"TextRun Highlight SCX111949552\" lang=\"ES-PE\" xml:lang=\"ES-PE\"><span class=\"NormalTextRun SCX111949552\">. </span></span><span class=\"TextRun Highlight SCX111949552\" lang=\"ES-PE\" xml:lang=\"ES-PE\"><span class=\"NormalTextRun SCX111949552\">En caso de robo o pérdida, comunícate inmediatamente a nuestro Centro de</span></span><span class=\"TextRun Highlight SCX111949552\" lang=\"ES-PE\" xml:lang=\"ES-PE\"><span class=\"NormalTextRun SCX111949552\"> Atención al Cliente</span></span> <span class=\"TextRun Highlight SCX111949552\" lang=\"ES-PE\" xml:lang=\"ES-PE\"><span class=\"NormalTextRun SCX111949552\">0801-00333 o 619-8931, </span></span><span class=\"TextRun Highlight SCX111949552\" lang=\"ES-PE\" xml:lang=\"ES-PE\"><span class=\"NormalTextRun SCX111949552\">para</span></span><span class=\"TextRun Highlight SCX111949552\" lang=\"ES-PE\" xml:lang=\"ES-PE\"><span class=\"NormalTextRun SCX111949552\"> solicitar el bloqueo y la </span></span><span class=\"TextRun Highlight SCX111949552\" lang=\"ES-PE\" xml:lang=\"ES-PE\"><span class=\"NormalTextRun SCX111949552\">reposición de tu tarjeta (según tarifario vigente)</span></span><span class=\"TextRun Highlight SCX111949552\" lang=\"ES-PE\" xml:lang=\"ES-PE\"><span class=\"NormalTextRun SCX111949552\">.</span></span><span class=\"EOP SCX111949552\"> </span>[/vc_column_text][/vc_accordion_tab][vc_accordion_tab title=\"¿Cómo puedo solicitar la reposición de mi tarjeta Plata?\" icon=\"\"][vc_column_text]\r\n<ul>\r\n 	<li data-listid=\"17\" data-aria-posinset=\"1\" data-aria-level=\"1\">Para solicitar la reposición de la tarjeta, escríbenos a reposiciones@tebca.com.pe o comunícate con nuestro Centro de Atención al Cliente 0801-00333 o 619-8931.</li>\r\n 	<li data-listid=\"17\" data-aria-posinset=\"2\" data-aria-level=\"1\">Recuerda que una vez confirmado los datos y el pago por concepto de reposición (ver tarifario vigente en Reposiciones), se establecerán los siguientes tiempos de entrega:\r\n- Lima: 5 días útiles\r\n- Provincia: 12 días útiles</li>\r\n</ul>\r\n[/vc_column_text][/vc_accordion_tab][vc_accordion_tab title=\"¿Qué hacer si la tarjeta es rechazada en algún comercio?\" icon=\"\"][vc_column_text]\r\n<ul>\r\n 	<li data-listid=\"17\" data-aria-posinset=\"1\" data-aria-level=\"1\">Asegúrate de realizar la transacción en un comercio afiliado a la Red MasterCard y Visa.</li>\r\n 	<li data-listid=\"17\" data-aria-posinset=\"2\" data-aria-level=\"1\">Verifica si tienes saldo disponible para pagar el importe total de tu compra.</li>\r\n 	<li data-listid=\"17\" data-aria-posinset=\"3\" data-aria-level=\"1\">Verifica  que el comercio afiliado haya procesado correctamente tu compra y que tu clave secreta sea la correcta.</li>\r\n 	<li data-listid=\"17\" data-aria-posinset=\"4\" data-aria-level=\"1\">Ante cualquier duda y/o consulta, recuerda que puedes comunicarte con nuestro Centro de Atención al Cliente 0801-00333 o 619-8931 para brindarte la orientación correspondiente.</li>\r\n</ul>\r\n[/vc_column_text][/vc_accordion_tab][/vc_accordion][/vc_column][/vc_row][vc_row css_animation=\"\" row_type=\"row\" type=\"full_width\" text_align=\"left\"][vc_column][vc_empty_space height=\"100px\"][/vc_column][/vc_row]', 'Personas', '', 'publish', 'closed', 'closed', '', 'personas', '', '', '2023-03-21 16:10:15', '2023-03-21 21:10:15', '', 0, 'https://platape.wpengine.com/?page_id=252', 4, 'page', '', 0);
