(254, 3, '2016-04-12 07:53:46', '2016-04-12 07:53:46', '[vc_row row_type=\"row\" type=\"grid\" text_align=\"left\" background_image=\"736\" css_animation=\"\" css=\".vc_custom_1482206460695{padding-top: 14px !important;padding-bottom: 73px !important;}\" el_class=\"full\"][vc_column el_class=\"black-btn\" css=\".vc_custom_1460386375532{margin-top: -50px !important;padding-top: 90px !important;padding-bottom: 100px !important;}\"][vc_column_text el_class=\"islider\" css=\".vc_custom_1480439278103{padding-top: 50px !important;}\"]<span style=\"color: white; font-size: 43px; line-height: 1.304347826086957em;\">Mayor comodidad\r\ny calidad de servicio</span>[/vc_column_text][/vc_column][/vc_row][vc_row row_type=\"row\" type=\"full_width\" text_align=\"center\" css_animation=\"\" css=\".vc_custom_1461262443527{padding-top: 15px !important;padding-bottom: 15px !important;}\" el_id=\"top-icon-links\"][vc_column][vc_column_text el_class=\"innerTemplateTopMenu\"]<a id=\"tarjetaProvis2\" href=\"#p8tabs\" rel=\"attachment wp-att-161\"><img class=\"alignnone size-full wp-image-161\" src=\"https://stplatape.wpenginepowered.com/wp-content/uploads/2016/04/Pagina-Internas-240222_03-4.png\" alt=\"Pagina-Internas-240222_03 (4)\" width=\"63\" height=\"50\" />   Sobre Plata</a>           <a id=\"beneficios2\" href=\"#p8tabs\" rel=\"attachment wp-att-162\"><img class=\"alignnone size-full wp-image-162\" src=\"https://stplatape.wpenginepowered.com/wp-content/uploads/2016/04/Pagina-Internas-240222_05-2.png\" alt=\"Pagina-Internas-240222_05 (2)\" width=\"48\" height=\"50\" />   Beneficios</a>           <a href=\"https://stplatape.wpenginepowered.com/wp-content/uploads/2016/06/emision-de-tarjetas-y-recargas.png\" rel=\"attachment wp-att-162\"><img class=\"alignnone wp-image-1020 size-full\" src=\"https://stplatape.wpenginepowered.com/wp-content/uploads/2016/06/emision-de-tarjetas-y-recargas.png\" width=\"64\" height=\"50\" /></a><a id=\"procesodepagos\" href=\"#proceso\" rel=\"attachment wp-att-162\">   Proceso de Pagos</a>[/vc_column_text][/vc_column][/vc_row][vc_row row_type=\"row\" type=\"grid\" text_align=\"left\" background_color=\"#f2f3f2\" css_animation=\"\" css=\".vc_custom_1460822286376{padding-top: 43px !important;padding-bottom: 43px !important;}\" el_class=\"full\"][vc_column width=\"1/3\"][vc_single_image image=\"270\" img_size=\"full\" alignment=\"center\" qode_css_animation=\"\" el_class=\"innerTemplateTopImage\"][vc_column_text el_class=\"blog-txt innerTemplateTopText\"]\r\n<h3 style=\"text-align: center; color: #085ca9;\">Ahorro</h3>\r\n&nbsp;\r\n<p style=\"text-align: center; font-size: 16px !important;\">Ahorra costos con Plata y agiliza sus gestiones de cobranza, olvidándose del manejo de vales de papel</p>\r\n\r\n[/vc_column_text][/vc_column][vc_column width=\"1/3\"][vc_single_image image=\"271\" img_size=\"full\" alignment=\"center\" qode_css_animation=\"\" el_class=\"innerTemplateTopImage\"][vc_column_text el_class=\"blog-txt innerTemplateTopText\"]\r\n<h3 style=\"text-align: center; color: #085ca9;\">Agilidad</h3>\r\n&nbsp;\r\n<p style=\"text-align: center; font-size: 16px !important;\">Procesa los pagos con mayor comodidad y recibe el dinero en tu cuenta en menos de 48 horas</p>\r\n\r\n[/vc_column_text][/vc_column][vc_column width=\"1/3\"][vc_single_image image=\"272\" img_size=\"full\" alignment=\"center\" qode_css_animation=\"\" el_class=\"innerTemplateTopImage\"][vc_column_text el_class=\"blog-txt innerTemplateTopText\"]\r\n<h3 style=\"text-align: center; color: #085ca9;\">Red Plata</h3>\r\n&nbsp;\r\n<p style=\"text-align: center; font-size: 16px !important;\">Al estar afiliado a la red Mastercard o Visa tu negocio estará listo para recibir a los miles de clientes Plata</p>\r\n\r\n[/vc_column_text][/vc_column][/vc_row][vc_row row_type=\"row\" type=\"grid\" text_align=\"left\" css_animation=\"\" css=\".vc_custom_1466627749592{margin-right: -25% !important;margin-left: -25% !important;border-bottom-width: 170px !important;padding-top: 80px !important;padding-bottom: 63px !important;}\" el_id=\"p8tabs\"][vc_column][vc_tabs style=\"horizontal\"][vc_tab title=\"Sobre Plata\" tab_id=\"68bdd577-fdae-9a554-31c1\"][vc_row_inner row_type=\"row\" type=\"grid\" text_align=\"left\" css_animation=\"\"][vc_column_inner width=\"1/2\"][vc_column_text el_class=\"extra-space\"]\r\n<h3 class=\"banner2\" style=\"color: #085ca9;\"><strong>SOBRE PLATA</strong></h3>\r\n<span style=\"font-weight: 400;\">Cada vez son más la empresas que pagan con Tarjetas Plata, se tú uno de los comercios que pueden recibir a estos miles de clientes.</span>\r\n\r\n<span style=\"font-weight: 400;\">Aceptar Plata es recibir un pago de forma rápida, cómoda y segura.</span>[/vc_column_text][/vc_column_inner][vc_column_inner width=\"1/2\"][vc_single_image image=\"1278\" img_size=\"large\" qode_css_animation=\"\"][/vc_column_inner][/vc_row_inner][/vc_tab][vc_tab title=\"Beneficios\" tab_id=\"0880033b-3442-0a554-31c1\"][vc_row_inner row_type=\"row\" type=\"grid\" text_align=\"left\" css_animation=\"\"][vc_column_inner width=\"1/2\"][vc_column_text el_class=\"extra-space\"]\r\n<h3 class=\"banner2\" style=\"color: #085ca9;\">BENEFICIOS</h3>\r\n<ul>\r\n	<li class=\"banner3text\">Acceso a nuevos clientes</li>\r\n	<li class=\"banner3text\">Menores tiempos de abono ya que los pagos se procesan en menos de 48 horas</li>\r\n	<li class=\"banner3text\">Posibilidad de efectuar cobros por montos exactos, sin tener que dar vuelto a los clientes</li>\r\n	<li class=\"banner3text\">Rapidez en la transacción</li>\r\n	<li class=\"banner3text\">Reducción de gastos operativos, servicios de recolección de valores y sistemas administrativos, de lectura de tickets etc.</li>\r\n	<li class=\"banner3text\">Seguridad, al evitar el extravío o robo de los cupones de papel</li>\r\n	<li class=\"banner3text\">Promueve la fidelidad entre los clientes y su comercio</li>\r\n</ul>\r\n[/vc_column_text][/vc_column_inner][vc_column_inner width=\"1/2\"][vc_single_image image=\"934\" img_size=\"large\" qode_css_animation=\"\"][/vc_column_inner][/vc_row_inner][/vc_tab][/vc_tabs][/vc_column][/vc_row][vc_row row_type=\"row\" type=\"grid\" text_align=\"left\" background_image=\"1243\" css_animation=\"\" css=\".vc_custom_1478790727669{padding-top: 60px !important;padding-bottom: 60px !important;background-image: url(http://70.32.115.119/~plataweb/wp-content/uploads/2016/04/Plata-Background-Azul.png?id=1365) !important;}\" el_class=\"full\" el_id=\"proceso\"][vc_column width=\"1/3\"][vc_single_image image=\"1276\" img_size=\"medium\" alignment=\"center\" qode_css_animation=\"\"][/vc_column][vc_column width=\"2/3\" el_class=\"contain-a\" css=\".vc_custom_1460506578330{padding-top: 30px !important;}\"][vc_column_text el_class=\"extra-space\"]\r\n<h2 class=\"banner2\" style=\"color: #085ca9;\"><span style=\"color: #ffffff;\"><strong>PROCESO DE PAGOS</strong></span></h2>\r\n<span style=\"font-weight: 400; color: #ffffff; font-size: 16px;\">Pasa la tarjeta por la terminal MasterCard o Visa e introduce el importe del consumo.</span>\r\n\r\n<span style=\"font-weight: 400; color: #ffffff; font-size: 16px;\">El titular deberá marcar su clave secreta y presionar la tecla Enter.</span>\r\n\r\n<span style=\"font-weight: 400; color: #ffffff; font-size: 16px;\">Una vez obtenido el comprobante, entregue una copia al cliente y conserve otra copia para su comercio, como constancia de la transacción realizada.</span>\r\n\r\n<span style=\"font-weight: 400; color: #ffffff; font-size: 16px;\">El valor de la compra será debitado de manera automática de la tarjeta del cliente y en el transcurso de 48 horas estará disponible en la cuenta de su establecimiento.</span>[/vc_column_text][/vc_column][/vc_row]', 'Comercios', '', 'publish', 'closed', 'closed', '', 'comercios', '', '', '2016-12-20 03:58:24', '2016-12-20 03:58:24', '', 0, 'http://70.32.115.119/~provisbonusweb/?page_id=254', 5, 'page', '', 0),
