(1351, 3, '2016-11-03 19:13:59', '2016-11-03 19:13:59', '[vc_row css_animation=\"\" row_type=\"row\" type=\"full_width\" text_align=\"left\"][vc_column css=\".vc_custom_1466638533050{margin-top: 30px !important;}\"][vc_column_text]\r\n<h3 style=\"text-align: left;\"><strong><span style=\"color: #005baa;\"><span style=\"font-size: 28px;\">ESTADÍSTICAS DE RECLAMOS</span></span></strong></h3>\r\n[/vc_column_text][/vc_column][/vc_row][vc_row css_animation=\"\" row_type=\"row\" type=\"full_width\" text_align=\"left\"][vc_column][vc_empty_space][/vc_column][/vc_row][vc_row css_animation=\"\" row_type=\"row\" type=\"full_width\" text_align=\"left\"][vc_column][vc_column_text]\r\n<ul>\r\n 	<li><a href=\"https://stplatape.wpenginepowered.com/wp-content/uploads/2023/07/Estadisticas-web-Plata-II-trim-23.pdf\">II Informe trimestral de reclamos 2023</a></li>\r\n 	<li><span style=\"vertical-align: inherit;\"><a href=\"https://stplatape.wpenginepowered.com/wp-content/uploads/2023/07/Estadisticas-web-Plata-I-trim-23-.pdf\">I Informe trimestral de reclamos 2023</a></span></li>\r\n 	<li>I<a href=\"https://stplatape.wpenginepowered.com/wp-content/uploads/2023/07/Estadisticas-web-Plata-IV-trim-22.pdf\">V <span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">Informe </span></span><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">trimestral de reclamos 2022</span></span></a></li>\r\n 	<li><a href=\"https://stplatape.wpenginepowered.com/wp-content/uploads/2022/10/Estadisticas-web-Plata-III-trim-22.pdf\"><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">I</span></span><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">II Informe trimestral de reclamos 2022</span></span></a></li>\r\n 	<li><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">I</span></span><a href=\"https://stplatape.wpenginepowered.com/wp-content/uploads/2022/07/Estadisticas-web-Plata-II-trim-22.pdf\"><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">I Informe trimestral de reclamos 2022</span></span></a></li>\r\n 	<li><a href=\"https://stplatape.wpenginepowered.com/wp-content/uploads/2022/07/Estadisticas-web-Plata-I-trim-22-V2.pdf\"><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">I Informe trimestral de reclamos 2022</span></span></a></li>\r\n 	<li><a href=\"https://stplatape.wpenginepowered.com/wp-content/uploads/2022/07/Estadisticas-web-Plata-IV-trim21-V2.pdf\"><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">IV Informe trimestral de reclamos 2021</span></span></span></span></a></li>\r\n 	<li><a href=\"https://stplatape.wpenginepowered.com/wp-content/uploads/2022/07/Estadisticas-web-Plata-III-trim21-V2.pdf\"><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">III Informe trimestral de reclamos 2021</span></span></span></span></a></li>\r\n 	<li><a href=\"https://stplatape.wpenginepowered.com/wp-content/uploads/2021/07/Estadisticas-web-Plata-II-trim21.pdf\"><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">II Informe trimestral de reclamos 2021</span></span></span></span></a></li>\r\n 	<li><a href=\"https://stplatape.wpenginepowered.com/wp-content/uploads/2021/04/Estadisticas-web-Plata-I-trim21.pdf\"><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">I Informe trimestral de reclamos 2021</span></span></span></span></a></li>\r\n 	<li><a href=\"https://stplatape.wpenginepowered.com/wp-content/uploads/2021/01/Estadisticas-web-P