span style=\"color: #333333; font-family: \'Comic Sans MS\', arial, verdana; font-size: large;\">Recarga tu tarjeta en establecimientos afiliados a lo largo de la ruta Palmari 1611 <strong>\"El Rápido\"</strong>, o en Agentes Vende Más</span></li>\r\n</ul>\r\n[/vc_column_text][vc_empty_space][/vc_column_inner][vc_column_inner width=\"1/2\"][vc_empty_space][vc_single_image image=\"1797\" img_size=\"full\" alignment=\"center\" qode_css_animation=\"\"][/vc_column_inner][/vc_row_inner][/vc_tab][vc_tab title=\"¿Cómo usar mi tarjeta?\" tab_id=\"0880033b-3442-06842-c166\"][vc_row_inner row_type=\"row\" type=\"grid\" text_align=\"left\" css_animation=\"\"][vc_column_inner][vc_empty_space][vc_single_image image=\"1807\" img_size=\"full\" alignment=\"center\" qode_css_animation=\"\"][vc_empty_space][vc_single_image image=\"1800\" img_size=\"full\" alignment=\"center\" qode_css_animation=\"\"][vc_empty_space][vc_single_image image=\"1801\" img_size=\"full\" alignment=\"center\" qode_css_animation=\"\"][/vc_column_inner][/vc_row_inner][/vc_tab][/vc_tabs][/vc_column][/vc_row][vc_row row_type=\"row\" type=\"full_width\" text_align=\"left\" css_animation=\"\"][vc_column][vc_empty_space height=\"50px\"][/vc_column][/vc_row]', 'Tarjeta Plata Transporte', '', 'publish', 'closed', 'closed', '', 'platatransporte', '', '', '2019-12-05 16:30:51', '2019-12-05 21:30:51', '', 0, 'https://stplatape.wpenginepowered.com/?page_id=1792', 3, 'page', '', 0),
