(1817, 3, '2019-12-27 16:15:49', '2019-12-27 21:15:49', '<p>[vc_row css_animation=\"\" row_type=\"row\" type=\"full_width\" text_align=\"left\" background_image=\"1836\" css=\".vc_custom_1629566616258{padding-top: 14px !important;padding-bottom: 73px !important;}\" el_class=\"full\" el_id=\"nodevice\"][vc_column el_class=\"black-btn\" css=\".vc_custom_1629563920300{margin-top: -50px !important;padding-top: 90px !important;padding-bottom: 100px !important;}\" offset=\"vc_hidden-sm vc_hidden-xs\"][vc_column_text]</p>\r\n<p>&nbsp;</p>\r\n<p>[/vc_column_text][/vc_column][/vc_row][vc_row full_width=\"stretch_row_content_no_spaces\" css_animation=\"\" row_type=\"row\" type=\"full_width\" text_align=\"center\" el_id=\"device\" css=\".vc_custom_1629566657339{margin-right: 0px !important;margin-left: 0px !important;padding-right: 0px !important;padding-left: 0px !important;background: #ffb508 url(https://stplatape.wpenginepowered.com/wp-content/uploads/2021/08/plata-prepago-mob2.jpg?id=1923) !important;background-position: center !important;background-repeat: no-repeat !important;background-size: contain !important;}\" el_class=\"full\"][vc_column el_class=\"black-btn\" offset=\"vc_hidden-lg vc_hidden-md\" css=\".vc_custom_1629565741584{margin-right: 0px !important;margin-left: 0px !important;padding-top: 190px !important;padding-right: 0px !important;padding-bottom: 100px !important;padding-left: 0px !important;}\"][vc_column_text]</p>\r\n<p>&nbsp;</p>\r\n<p>[/vc_column_text][/vc_column][/vc_row][vc_row css_animation=\"\" row_type=\"row\" type=\"grid\" text_align=\"left\" css=\".vc_custom_1466556271416{margin-right: -25% !important;margin-left: -25% !important;border-bottom-width: 170px !important;padding-top: 80px !important;padding-bottom: 63px !important;}\" el_id=\"p8tabs\"][vc_column][vc_tabs style=\"horizontal\"][vc_tab title=\"¿Cómo funciona mi tarjeta?\" tab_id=\"1477581906472-3-1\"][vc_row_inner row_type=\"row\" type=\"grid\" text_align=\"left\" css_animation=\"\"][vc_column_inner width=\"1/2\"][vc_empty_space][vc_column_text]</p>\r\n<h3><span style=\"color: #085ca9;\"><strong>¿Cómo la uso?</strong></span></h3>\r\n<p>[/vc_column_text][vc_empty_space height=\"22px\"][vc_column_text]</p>\r\n<ul>\r\n<li><span style=\"color: #000000;\">Asegúrate que el vendedor la active. Solo deberás brindar tu número de DNI, celular, nombre, dirección, mail y firma</span></li>\r\n</ul>\r\n<p>&nbsp;</p>\r\n<ul>\r\n<li><span style=\"color: #000000;\">Asegúrate de recargarla con saldo para comprar. Sólo podrás gastar el saldo recargado</span></li>\r\n</ul>\r\n<p>[/vc_column_text][vc_empty_space][vc_column_text]</p>\r\n<h3><span style=\"color: #085ca9;\"><strong>¿Dónde la recargo?</strong></span></h3>\r\n<p>[/vc_column_text][vc_empty_space height=\"22px\"][vc_column_text]</p>\r\n<ul>\r\n<li><span style=\"color: #000000;\">Recarga tu tarjeta en cualquier bodega que tenga recargas y pago de servicios VendeMás.</span><br />\r\n<span style=\"color: #000000;\">Para conocer los puntos de recarga cercanos ingresa aquí: <a href=\"https://stplatape.wpenginepowered.com/wp-content/uploads/2020/02/Puntos-Vendemás-actualizado.pdf\" target=\"_blank\" rel=\"noopener noreferrer\">Comercios Afiliados</a></span></li>\r\n</ul>\r\n<p>[/vc_column_text][vc_empty_space][vc_column_text]</p>\r\n<h3><span style=\"color: #085ca9;\"><strong>¿Dónde puedo retirar el efectivo?</strong></span></h3>\r\n<p>[/vc_column_text][vc_empty_space height=\"22px\"][vc_column_text]</p>\r\n<ul>\r\n<li><span style=\"color: #000000;\">Retira efectivo en cualquier agente Global Net</span></li>\r\n</ul>\r\n<p>[/vc_column_text][vc_empty_space height=\"22px\"][vc_column_text]</p>\r\n<h3><span style=\"color: #085ca9;\"><strong>¿Dónde puedo comprar?</strong></span></h3>\r\n<p>[/vc_column_text][vc_empty_space height=\"22px\"][vc_column_text]</p>\r\n<ul>\r\n<li><span style=\"color: #000000;\">Úsala para todas tus compras en establecimientos afilados a VISA y online</span></li>\r\n</ul>\r\n<p>[/vc_column_text][/vc_column_inner][vc_column_inner width=\"1/2\"][vc_empty_space][vc_single_image image=\"1826\" img_size=\"full\" alignment=\"center\" qode_css_animation=\"\"][/vc_column_inner][/vc_row_inner][/vc_tab][vc_tab title=\"Beneficios\" tab_id=\"0880033b-3442-06842-c166\"][vc_row_inner row_type=\"row\" type=\"grid\" text_align=\"left\" css_animation=\"\"][vc_column_inner width=\"1/2\"][vc_empty_space][vc_column_text]</p>\r\n<h3><span style=\"color: #085ca9;\"><strong>1- ¡Tienes el poder: Tú decides cuánto gastar!</strong></span></h3>\r\n<p>[/vc_column_text][vc_empty_space height=\"22\"][vc_column_text]</p>\r\n<ul>\r\n<li><span style=\"color: #000000;\">Puedes gastar como máximo el saldo disponible en tu tarjeta</span></li>\r\n</ul>\r\n<p>[/vc_column_text][vc_empty_space height=\"32\"][vc_column_text]</p>\r\n<h3><span style=\"color: #085ca9;\"><strong>2- ¡<b>Compra más seguro sin cargar efectivo</b>!</strong></span></h3>\r\n<p>[/vc_column_text][vc_empty_space height=\"22\"][vc_column_text]</p>\r\n<ul>\r\n<li><span style=\"color: #000000;\"> Realiza todas tus compras de manera segura sin la necesidad de cargar dinero en efectivo. No pagas comisiones adicionales por comprar con tu tarjeta, el monto consumido es igual al monto de compra.</span></li>\r\n</ul>\r\n<p>[/vc_column_text][vc_empty_space height=\"32\"][vc_column_text]</p>\r\n<h3><span style=\"color: #085ca9;\"><strong>3- ¡<b>Más de 7,000 establecimientos disponibles para comprar</b>!</strong></span></h3>\r\n<p>[/vc_column_text][vc_empty_space height=\"22\"][vc_column_text]</p>\r\n<ul>\r\n<li><span style=\"color: #000000;\">Úsala en miles de establecimientos afilados a VISA, en canales físico u online.</span></li>\r\n</ul>\r\n<p>[/vc_column_text][vc_empty_space height=\"32\"][vc_column_text]</p>\r\n<h3><span style=\"color: #085ca9;\"><strong>3- B<b>eneficios en Entel y Cineplanet</b></strong></span></h3>\r\n<p>[/vc_column_text][vc_empty_space height=\"22\"][vc_column_text]</p>\r\n<ul>\r\n<li><span style=\"color: #000000;\">Hasta el 30 De Abril del 2020 tendrás los siguientes beneficios con tu tarjeta Plata Prepago</span></li>\r\n</ul>\r\n<p>[/vc_column_text][vc_empty_space height=\"22\"][vc_single_image image=\"1828\" img_size=\"full\" alignment=\"center\" qode_css_animation=\"\"][vc_column_text]</p>\r\n<h6 style=\"text-align: center;\"><a href=\"https://docs.google.com/document/d/1MZ93a4Eh3FyNxgGa2sXXCw_oLvTCWUiqVSHtmwIp8D0/edit?usp=sharing\">*Ver términos y condiciones</a></h6>\r\n<p>[/vc_column_text][vc_empty_space height=\"22\"][vc_single_image image=\"1829\" img_size=\"full\" alignment=\"center\" qode_css_animation=\"\"][vc_column_text]</p>\r\n<h6 style=\"text-align: center;\"><a href=\"https://docs.google.com/document/d/1VvR-2hR7JJSVHHGFBbH8dF1C7nzxzEHAEgp1OMxUK7Y/edit?usp=sharing\">*Ver términos y condiciones</a></h6>\r\n<p>[/vc_column_text][vc_empty_space height=\"22\"][vc_column_text]</p>\r\n<p style=\"text-align: center;\"><span style=\"color: #000000;\">*En portabilidad, los clientes recibirán 10,500 MB por las primeras 3 recargas de S/29 realizadas en los 3 primeros meses (regular 7,000 MB)</span></p>\r\n<p>[/vc_column_text][/vc_column_inner][vc_column_inner width=\"1/2\"][vc_single_image image=\"1827\" img_size=\"full\" alignment=\"center\" qode_css_animation=\"\"][/vc_column_inner][/vc_row_inner][/vc_tab][vc_tab title=\"Preguntas Frecuentes\" tab_id=\"1577479064399-2-5\"][vc_row_inner row_type=\"row\" type=\"grid\" text_align=\"left\" css_animation=\"\"][vc_column_inner][vc_empty_space][vc_column_text]</p>\r\n<h3><span style=\"color: #085ca9;\"><strong>1- En nuestros canales</strong></span></h3>\r\n<p>[/vc_column_text][vc_empty_space height=\"22px\"][vc_column_text]</p>\r\n<ul>\r\n<li><span style=\"color: #000000;\"><span style=\"color: #085ca9;\"><strong>ATENCIÓN AL CLIENTE:</strong></span><br />\r\n</span><span style=\"color: #000000;\">Llama a nuestro Centro de Atención al Cliente (01) 619-8931, servicio que se encuentra de Lunes a Domingo de 6:00 am a 10:00 pm</span></li>\r\n</ul>\r\n<p>[/vc_column_text][vc_empty_space height=\"22px\"][vc_column_text]</p>\r\n<ul>\r\n<li><span style=\"color: #000000;\"><span style=\"color: #085ca9;\"><strong>WEB:</strong></span><br />\r\n<a href=\"https://stplatape.wpenginepowered.com/\">www.stplatape.wpenginepowered.com</a>, ingresa a Conexión Online/ Conexión Personas, si estas registrado digita tu usuario y clave, podrás obtener el detalle de todas tus operaciones realizadas con la tarjeta</span></li>\r\n</ul>\r\n<p>[/vc_column_text][vc_empty_space height=\"22px\"][vc_column_text]</p>\r\n<ul>\r\n<li><span style=\"color: #000000;\"><span style=\"color: #085ca9;\"><strong>APP:</strong></span><br />\r\nDescarga el App Servitebca, acceso móvil en las tiendas de aplicaciones: Google Play (Android), App Store (iPhone)</span></li>\r\n</ul>\r\n<p>[/vc_column_text][vc_empty_space height=\"22px\"][vc_column_text]</p>\r\n<ul>\r\n<li><span style=\"color: #000000;\"><span style=\"color: #085ca9;\"><strong>FACEBOOK MESSENGER:</strong></span><br />\r\nEscribe en Facebook Messenger a MIA Tebca y consulta tu saldo</span></li>\r\n</ul>\r\n<p>[/vc_column_text][vc_empty_space][vc_column_text]</p>\r\n<h3><span style=\"color: #085ca9;\"><strong>2- En los recibos de tus compras</strong></span></h3>\r\n<p>[/vc_column_text][vc_empty_space height=\"22px\"][vc_column_text]</p>\r\n<ul>\r\n<li><span style=\"color: #000000;\">En la parte inferior de los recibos de Visa que te entreguen luego de realizar tus compras se indica el saldo disponible.</span></li>\r\n</ul>\r\n<p>[/vc_column_text][/vc_column_inner][/vc_row_inner][/vc_tab][/vc_tabs][/vc_column][/vc_row][vc_row css_animation=\"\" row_type=\"row\" type=\"full_width\" text_align=\"left\"][vc_column][/vc_column][/vc_row]</p>\r\n', 'Tarjeta Plata Prepago', '', 'publish', 'closed', 'closed', '', 'plataprepago', '', '', '2021-08-21 12:24:18', '2021-08-21 17:24:18', '', 0, 'https://stplatape.wpenginepowered.com/?page_id=1817', 3, 'page', '', 0),
