(2129, 13, '2023-08-28 14:27:15', '2023-08-28 19:27:15', '[vc_row css_animation=\"\" row_type=\"row\" type=\"grid\" text_align=\"left\" background_image=\"1474\" css=\".vc_custom_1482206418295{padding-top: 14px !important;padding-bottom: 73px !important;}\" el_class=\"full\"][vc_column el_class=\"black-btn\" css=\".vc_custom_1460386375532{margin-top: -50px !important;padding-top: 90px !important;padding-bottom: 100px !important;}\"][vc_column_text el_class=\"islider\" css=\".vc_custom_1480454740048{padding-top: 50px !important;}\"]\n<p style=\"text-align: right;\"><span style=\"color: white; font-size: 43px; line-height: 1.304347826086957em;\">Plata es la solución eficaz\npara el manejo de fondos</span></p>\n[/vc_column_text][/vc_column][/vc_row][vc_row css_animation=\"\" row_type=\"row\" type=\"full_width\" text_align=\"center\" css=\".vc_custom_1460519024274{padding-top: 15px !important;padding-bottom: 15px !important;}\"][vc_column offset=\"vc_hidden-sm vc_hidden-xs\"][vc_column_text el_class=\"innerTemplateTopMenu\"]<a id=\"programas\" class=\"tab-link\" href=\"#p8tabs\" rel=\"attachment wp-att-162\"><img class=\"alignnone size-full wp-image-162\" src=\"/wp-content/uploads/2016/06/emision-de-tarjetas-y-recargas.png\" alt=\"Pagina-Internas-240222_05 (2)\" width=\"48\" height=\"50\" /> Programas</a>     <a id=\"beneficios\" class=\"tab-link\" href=\"#p8tabs\" rel=\"attachment wp-att-162\"><img class=\"alignnone size-full wp-image-162\" src=\"/wp-content/uploads/2016/04/Pagina-Internas-240222_05-2.png\" alt=\"Pagina-Internas-240222_05 (2)\" width=\"48\" height=\"50\" /> Beneficios</a>     <a id=\"emision\" href=\"#emision-facturacion\" rel=\"attachment wp-att-165\"><img class=\"alignnone size-full wp-image-165\" src=\"http://platape.wpengine.com/wp-content/uploads/2016/06/servicios-en-linea.png\" alt=\"Pagina-Internas-240222_11\" width=\"36\" height=\"50\" /> Emisión y Recarga</a>     <a id=\"serviciosEnLinea\" class=\"tab-link\" href=\"#p8tabs\" rel=\"attachment w